queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?required_experience WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:position_id ?cg . ?child a :Legal_Positions ; p:id ?cg . ?l p:firm_id ?pg . ?parent a :Law_Firms ; p:id ?pg . } GROUP BY ?child }
  ?child p:required_experience ?required_experience .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Law_Firms } }
  FILTER(?nf = ?total)
}

